#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long maxOm = 0, cur = 0;
        for (int i = 0; i < N; ++i) {
            long long x; scanf("%lld", &x);
            if (x > 0) { cur++; if (cur > maxOm) maxOm = cur; }
            else cur = 0;
        }
        // store Om's max, now read Addy's array
        long long maxAddy = 0; cur = 0;
        for (int i = 0; i < N; ++i) {
            long long x; scanf("%lld", &x);
            if (x > 0) { cur++; if (cur > maxAddy) maxAddy = cur; }
            else cur = 0;
        }
        if (maxOm > maxAddy) printf("Om\n");
        else if (maxAddy > maxOm) printf("Addy\n");
        else printf("Draw\n");
    }
    return 0;
}

