#!/usr/bin/env python3
import sys

def solve():
    data = list(map(int, sys.stdin.read().strip().split()))
    if not data:
        return
    it = iter(data)
    T = next(it)
    out_lines = []
    for _ in range(T):
        N = next(it)
        max_om = cur = 0
        for _ in range(N):
            x = next(it)
            if x > 0:
                cur += 1
                if cur > max_om:
                    max_om = cur
            else:
                cur = 0
        max_addy = cur = 0
        for _ in range(N):
            x = next(it)
            if x > 0:
                cur += 1
                if cur > max_addy:
                    max_addy = cur
            else:
                cur = 0
        if max_om > max_addy:
            out_lines.append("Om")
        elif max_addy > max_om:
            out_lines.append("Addy")
        else:
            out_lines.append("Draw")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    solve()

